<?php declare(strict_types=1); namespace App\Http\Controllers\Btaq; use App\Http\Controllers\Controller; use App\Models\{BtaqGroup,BtaqSchedule,BtaqSession,BtaqStudentProgress,Student}; use Symfony\Component\HttpFoundation\StreamedResponse; final class BtaqReportController extends Controller{public function index(){return view('btaq.reports.index',$this->data());} public function missingSessions(){return view('btaq.reports.missing-sessions',$this->data());} public function unassignedStudents(){return view('btaq.reports.unassigned-students',$this->data()+['students'=>Student::where('is_active',true)->whereDoesntHave('enrollments')->paginate(15)]);} public function export():StreamedResponse{return response()->streamDownload(function(){echo "jenis,jumlah\nkelompok,".BtaqGroup::count()."\nsesi,".BtaqSession::count()."\n";},'laporan-btaq.csv',['Content-Type'=>'text/csv']);} public function print(){return view('btaq.reports.print',$this->data());} private function data():array{return ['summary'=>['groups'=>BtaqGroup::where('is_active',true)->count(),'students'=>\App\Models\BtaqGroupStudent::where('status','active')->distinct('student_id')->count('student_id'),'sessions'=>BtaqSession::count(),'submitted'=>BtaqSession::whereIn('status',['submitted','verified'])->count(),'missing'=>BtaqSchedule::where('is_active',true)->count(),'pending'=>BtaqSession::where('status','submitted')->count(),'guidance'=>BtaqStudentProgress::where('achievement_status','perlu_bimbingan')->count(),'promoted'=>\App\Models\BtaqProgressHistory::whereMonth('created_at',now()->month)->count()],'groups'=>BtaqGroup::withCount('students')->paginate(15)];}}
